args.command:
cat << 'EOF' > fix_activities.py
import yaml
with open('curriculum/l2-uk-en/a1/activities/the-ukrainian-alphabet.yaml', 'r') as f:
    data = yaml.safe_load(f)

for activity in data:
    if activity.get('type') == 'anagram':
        for item in activity.get('items', []):
            if item.get('answer') == 'молоко':
                item['scrambled'] = 'О К О Л О М'
    if activity.get('type') == 'fill-in':
        for item in activity.get('items', []):
            if '(mom)' in item.get('sentence', ''):
                item['sentence'] = 'м _ м а 👩'
            if '(dad)' in item.get('sentence', ''):
                item['sentence'] = 'т _ т о 👨'
            if '(cat)' in item.get('sentence', ''):
                item['sentence'] = 'к _ т 🐈'
            if '(city)' in item.get('sentence', ''):
                item['sentence'] = 'м _ с т о 🏙️'
            if '(forest)' in item.get('sentence', ''):
                item['sentence'] = 'л _ с 🌲'
            if '(juice)' in item.get('sentence', ''):
                item['sentence'] = 'с _ к 🧃'

with open('curriculum/l2-uk-en/a1/activities/the-ukrainian-alphabet.yaml', 'w') as f:
    yaml.dump(data, f, allow_unicode=True, sort_keys=False)
EOF
.venv/bin/python fix_activities.py
